import { defineTool } from "npm:@lovable.dev/mcp-js@0.20.0";
import { z } from "npm:zod@^3.25.76";
import { products } from "npm:@/data/products";
var list_products_default = defineTool({
  name: "list_products",
  title: "Listar productos MaxRico",
  description: "Devuelve el cat\xE1logo de productos artesanales colombianos (empanadas, teque\xF1os, PandeBono, arepas, chorizos, etc.) con precio normal, precio socio y disponibilidad.",
  inputSchema: {
    category: z.string().optional().describe("Filtro opcional por categor\xEDa (ej: Empanadas, PandeBono, Arepas)."),
    onlyAvailable: z.boolean().optional().describe("Si es true, excluye productos agotados.")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ category, onlyAvailable }) => {
    const filtered = products.filter((p) => {
      if (category && p.category.toLowerCase() !== category.toLowerCase()) return false;
      if (onlyAvailable && p.soldOut) return false;
      return true;
    });
    const rows = filtered.map((p) => ({
      id: p.id,
      slug: p.slug,
      name: p.name,
      category: p.category,
      price_eur: p.price,
      member_price_eur: p.memberPrice,
      pack_size: p.packSize,
      weight: p.weight ?? null,
      sold_out: !!p.soldOut
    }));
    return {
      content: [{ type: "text", text: JSON.stringify(rows, null, 2) }],
      structuredContent: { products: rows }
    };
  }
});

