import { defineTool as defineTool2 } from "npm:@lovable.dev/mcp-js@0.20.0";
import { z as z2 } from "npm:zod@^3.25.76";
import { products as products2 } from "npm:@/data/products";
var get_product_default = defineTool2({
  name: "get_product",
  title: "Detalle de producto",
  description: "Devuelve la ficha completa de un producto MaxRico por slug o id: descripci\xF3n, ingredientes, preparaci\xF3n, conservaci\xF3n, precios y disponibilidad.",
  inputSchema: {
    slugOrId: z2.string().min(1).describe("Slug o id del producto.")
  },
  annotations: { readOnlyHint: true, idempotentHint: true, openWorldHint: false },
  handler: ({ slugOrId }) => {
    const key = slugOrId.toLowerCase();
    const p = products2.find(
      (x) => x.slug.toLowerCase() === key || x.id.toLowerCase() === key
    );
    if (!p) {
      return {
        content: [{ type: "text", text: `No se encontr\xF3 ning\xFAn producto con "${slugOrId}".` }],
        isError: true
      };
    }
    const row = {
      id: p.id,
      slug: p.slug,
      name: p.name,
      category: p.category,
      description: p.description,
      ingredients: p.ingredients,
      preparation: p.preparation,
      conservation: p.conservation,
      price_eur: p.price,
      original_price_eur: p.originalPrice ?? null,
      member_price_eur: p.memberPrice,
      pack_size: p.packSize,
      weight: p.weight ?? null,
      format: p.format ?? null,
      sold_out: !!p.soldOut,
      badge: p.badge ?? null,
      url: `https://maxrico.es/producto/${p.slug}`
    };
    return {
      content: [{ type: "text", text: JSON.stringify(row, null, 2) }],
      structuredContent: { product: row }
    };
  }
});

